def max_subarray_sum(nums):
    if not nums:
        return 0
    # Initialize both to the first element of the array
    current_max = nums[0]
    global_max = nums[0]
    for num in nums:
        current_max = max(num, current_max + num)
        global_max = max(global_max, current_max)
    return global_max

